#include <bits/stdc++.h>
using namespace std;
int m,n,p[10004],t[10004],dp[10004];
int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&p[i],&t[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            if(j>=t[i])
                dp[j]=max(dp[j],dp[j-t[i]]+p[i]);
    printf("%d",dp[m]);
    return 0;
}
